code = """import json

# Load data simpler way
civic_docs = locals()['var_functions.query_db:54']
funding = locals()['var_functions.query_db:55']

# Convert to lists
if type(civic_docs) is str:
    civic_docs = json.load(open(civic_docs))
else:
    civic_docs = list(civic_docs)

if type(funding) is str:
    funding = json.load(open(funding))
else:
    funding = list(funding)

# Build funding map
funding_map = {}
for rec in funding:
    name = rec['Project_Name']
    amount = int(rec['Amount'])
    funding_map[name] = amount

# Find projects
total = 0
found = []

# Check funding for 2022 disaster projects
for name, amount in funding_map.items():
    if '2022' in name:
        if '(FEMA' in name or '(CalOES' in name or '(CalJPIA' in name:
            total += amount
            found.append([name, amount])

# Check civic docs
for doc in civic_docs:
    txt = doc.get('text', '')
    if '2022' in txt:
        lines = txt.split('\n')
        for i, line in enumerate(lines):
            line = line.strip()
            if len(line) > 10 and '(FEMA' not in line and '(CalOES' not in line and '(CalJPIA' not in line:
                continue
            for j in range(max(0,i-3), min(len(lines),i+4)):
                if '2022' in lines[j]:
                    if line in funding_map and line not in [p[0] for p in found]:
                        total += funding_map[line]
                        found.append([line, funding_map[line]])
                    break

result = {'total_funding': total, 'project_count': len(found), 'projects': found}
print('__RESULT__:')
print(json.dumps(result))"""

